import type { Preview } from '@storybook/web-components-vite';
import { setCustomElementsManifest } from '@storybook/web-components-vite';
import { html } from 'lit';

// Built brand tokens — base dark theme. Generated by `npm run build` at the
// repo root (build/css is git-ignored, so run the build before Storybook).
// Importing the CSS defines every --color-*/--font-*/--spacing-* custom
// property on :root, which is all the rr-* components need to theme.
import '../../../build/css/variables.css';

// Feed Storybook the generated Custom Elements Manifest so autodocs builds the
// prop tables, control types, and component descriptions from the single source
// (JSDoc → `cem analyze` → custom-elements.json) instead of hand-maintained
// argTypes. Committed artifact; regenerated by `npm run build:meta`.
import customElements from '../custom-elements.json';
setCustomElementsManifest(customElements);

const preview: Preview = {
  // Generate an autodocs page for every component from the CEM above.
  tags: ['autodocs'],
  parameters: {
    // The canvas is themed by the decorator below + preview-head.html, so the
    // built-in backgrounds addon would only fight the token-driven surface.
    backgrounds: { disable: true },
    controls: { expanded: true },
  },
  decorators: [
    (story) => html`
      <div
        style="
          background: var(--color-background-default);
          color: var(--color-foreground-default);
          font: var(--font-body-large);
          padding: var(--spacing-component);
          min-height: 100vh;
          box-sizing: border-box;
        "
      >
        ${story()}
      </div>
    `,
  ],
};

export default preview;
